#include <bits/stdc++.h>
using namespace std;
long long n;
int main(){
	cin>>n;
	for(long long i=1;i<=n; i++) {
		for(long long j=1;j<=n-i;j++) {
			cout<<" ";
		}
		for(long long j=1; j<=2*i-1; j++) {
			int a=(sqrt(j));
			if(a*a==j){
				cout<<"!";
			}else{
				cout<<"#";
			}
		}
		cout<<"\n";
	}
	return 0;
}
